#include<bits/stdc++.h>
using namespace std;
int n,m;
int in[100010],out[100010];
bool vis[200010];
deque<int> mp[100010];
vector<int> v;
void dfs(int x)
{
    while(!mp[x].empty())
    {
        int tmp=mp[x][0];
        mp[x].pop_front();
        dfs(tmp);
    }
    v.push_back(x);
}
int main()
{
    scanf("%d%d",&n,&m);
    for(int i=1;i<=m;i++)
    {
        int u,v;
        scanf("%d%d",&u,&v);
        in[v]++;
        out[u]++;
        mp[u].push_back(v);
    }
    int flag1=0,now1=1,flag2=0,now2=0;
    for(int i=1;i<=n;i++)
    {
        if(in[i]+1==out[i])
        {
            flag1++;
            now1=i;
        }
        else if(in[i]==out[i]+1)
        {
            flag2++;
            now2=i;
        }
        else if(in[i]!=out[i])
        {
            printf("No");
            return 0;
        }
    }
    if((flag1!=1||flag2!=1)&&(flag1!=0||flag2!=0))
    {
        printf("No");
        return 0;
    }
    for(int i=1;i<=n;i++)
    {
        sort(mp[i].begin(),mp[i].end());
    }
    dfs(now1);
    reverse(v.begin(),v.end());
    for(int i:v)
    {
        printf("%d ",i);
    }
    return 0;
}
